kids = defaultdict(list)
for t in tasks:
    if t['parentId']: kids[t['parentId']].append(t)
for k in kids: kids[k].sort(key=lambda t: t['childOrder'])

def depth(t):
    d=0
    while t['parentId'] and t['parentId'] in byid:
        d+=1; t=byid[t['parentId']]
    return d
print('max depth:', max(depth(t) for t in tasks))
print('grandchildren exist:', any(depth(t)>1 for t in tasks))
# orphan subtasks (parent not in active set)
