    "6gqMPfH9QJ3JM7Hh": "Backlog",  # Flow
}
EXISTING_AREAS = {"Health": "Ntj9urZm", "Sleep": "AawwDT12"}  # id prefixes in Things

tasks = json.load(open(os.path.join(SCRATCH, "tasks.json")))["results"]
projects = {p["id"]: p for p in json.load(open(os.path.join(SCRATCH, "projects.json")))["results"]}

def path_parts(pid):
    parts = []
    while pid:
        p = projects[pid]
        parts.append(p["name"])
        pid = p["parentId"]
    return list(reversed(parts))

# ---- classify tasks -------------------------------------------------------
byid = {t["id"]: t for t in tasks}
kids = defaultdict(list)
for t in tasks:
    if t["parentId"]:
        kids[t["parentId"]].append(t)
for k in kids:
    kids[k].sort(key=lambda t: t["childOrder"])

recurring_keys = {(t["projectId"], t["content"])
                  for t in tasks if t["due"] and t["due"].get("isRecurring")}

def is_expanded_dupe(t):
    return (not t["parentId"]
            and (t["projectId"], t["content"]) in recurring_keys
            and not (t["due"] and t["due"].get("isRecurring")))

top = [t for t in tasks if not t["parentId"] and not is_expanded_dupe(t)]

# ---- structure ------------------------------------------------------------
paths_with_tasks = sorted({tuple(path_parts(t["projectId"])) for t in top})
areas_needed = sorted({p[0] for p in paths_with_tasks if p[0] != "Inbox"})
projects_needed = sorted({p for p in paths_with_tasks if len(p) > 1})

