    due = t["due"]
    if due and due.get("isRecurring"):
        extra.append(f"Repeats: {due.get('string')}")
    elif due and "T" in (due.get("date") or ""):
        extra.append(f"Time: {due['date'].split('T')[1][:5]}")
    if t.get("duration"):
        d = t["duration"]
        extra.append(f"Duration: {d['amount']} {d['unit']}s" if d["amount"] != 1
                     else f"Duration: 1 {d['unit']}")
    if t.get("sectionId") and t["sectionId"] in SECTIONS:
        extra.append(f"Section: {SECTIONS[t['sectionId']]}")
    if extra:
        parts.append("(from Todoist: " + "; ".join(extra) + ")")
    return "\n\n".join(parts)

order = {tuple(pp): i for i, pp in enumerate(paths_with_tasks)}
top.sort(key=lambda t: (order[tuple(path_parts(t["projectId"]))], t["childOrder"]))

n = 0
for t in top:
    pp = tuple(path_parts(t["projectId"]))
    args = ["add", t["content"]]
    if len(pp) > 1:
        args += ["--project", proj_ref[pp]]
    elif pp[0] != "Inbox":
        args += ["--area", area_ref[pp[0]]]
    if t["due"] and t["due"].get("date"):
        args += ["--when", t["due"]["date"].split("T")[0]]
    if t.get("deadline"):
        args += ["--deadline", t["deadline"]["date"]]
    note = note_for(t)
    if note:
        args += ["--notes", note]
    if t["id"] in kids:
        args += ["--checklist", ",".join(c["content"] for c in kids[t["id"]])]
    run(f"task:{t['id']}", args)
    n += 1
    if n % 20 == 0:
        print(f"...{n}/{len(top)} todos", flush=True)

print(f"DONE: {len(area_ref) - len(EXISTING_AREAS)} areas, "
      f"{len(projects_needed)} projects, {len(top)} todos", flush=True)

