        if extra:
            raise CliError(f"unexpected argument {extra[0]!r} for `{cmd.name}`")
    for a in cmd.args:
        if a.required and not getattr(ns, a.name):
            raise CliError(f"missing argument <{a.name}> for `{cmd.name}`")
